import React, { useEffect, useState } from 'react';
import { teachersAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { Search, Plus, Edit, Trash2, Eye, Key, ToggleLeft, ToggleRight } from 'lucide-react';

const ManageTeachers = () => {
  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({ position: '', employmentStatus: '' });
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [selectedTeacher, setSelectedTeacher] = useState(null);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    email: '', password: '', firstName: '', middleName: '', lastName: '',
    gender: '', position: 'Instructor', employmentStatus: 'Full Time',
    sectionAdvisory: '', coursesHandled: '', degree: '', university: '',
    yearsOfService: 0, expertise: []
  });

  useEffect(() => {
    fetchTeachers();
  }, [filters]);

  const fetchTeachers = async () => {
    setLoading(true);
    try {
      const response = await teachersAPI.getAll({ ...filters, search: searchTerm });
      if (response.data.success) {
        setTeachers(response.data.teachers);
      }
    } catch (error) {
      console.error('Error fetching teachers:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchTeachers();
  };

  const handleAddTeacher = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await teachersAPI.create(formData);
      toast.success('Teacher added successfully');
      setShowAddModal(false);
      resetForm();
      fetchTeachers();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to add teacher');
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateTeacher = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await teachersAPI.update(selectedTeacher.id, formData);
      toast.success('Teacher updated successfully');
      setShowEditModal(false);
      fetchTeachers();
    } catch (error) {
      toast.error('Failed to update teacher');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteTeacher = async (id) => {
    if (!window.confirm('Are you sure you want to delete this teacher?')) return;
    try {
      await teachersAPI.delete(id);
      toast.success('Teacher deleted');
      fetchTeachers();
    } catch (error) {
      toast.error('Failed to delete teacher');
    }
  };

  const handleResetPassword = async (id) => {
    const newPassword = prompt('Enter new password (min 6 characters):');
    if (!newPassword || newPassword.length < 6) return;
    try {
      await teachersAPI.resetPassword(id, newPassword);
      toast.success('Password reset successfully');
    } catch (error) {
      toast.error('Failed to reset password');
    }
  };

  const resetForm = () => {
    setFormData({
      email: '', password: '', firstName: '', middleName: '', lastName: '',
      gender: '', position: 'Instructor', employmentStatus: 'Full Time',
      sectionAdvisory: '', coursesHandled: '', degree: '', university: '',
      yearsOfService: 0, expertise: []
    });
  };

  const openEditModal = (teacher) => {
    setSelectedTeacher(teacher);
    setFormData({
      firstName: teacher.first_name || '',
      middleName: teacher.middle_name || '',
      lastName: teacher.last_name || '',
      gender: teacher.gender || '',
      email: teacher.email || '',
      position: teacher.position || 'Instructor',
      employmentStatus: teacher.employment_status || 'Full Time',
      sectionAdvisory: teacher.section_advisory || '',
      coursesHandled: teacher.courses_handled || '',
      degree: teacher.degree || '',
      university: teacher.university || '',
      yearsOfService: teacher.years_of_service || 0,
      expertise: teacher.expertise || []
    });
    setShowEditModal(true);
  };

  const openViewModal = (teacher) => {
    setSelectedTeacher(teacher);
    setShowViewModal(true);
  };

  const expertiseOptions = ['Web Development', 'Mobile Development', 'Data Science', 'Networking', 'AI / Machine Learning', 'Cybersecurity'];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-secondary-800">Manage Teachers</h1>
        <button
          onClick={() => { resetForm(); setShowAddModal(true); }}
          className="btn-primary flex items-center gap-2"
        >
          <Plus className="w-4 h-4" />
          Add Teacher
        </button>
      </div>

      {/* Filters */}
      <Card>
        <form onSubmit={handleSearch} className="flex flex-wrap gap-4">
          <div className="flex-1 min-w-[200px] relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-secondary-400" />
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search teachers..."
              className="input-field pl-10"
            />
          </div>
          <select
            value={filters.position}
            onChange={(e) => setFilters(prev => ({ ...prev, position: e.target.value }))}
            className="input-field w-auto"
          >
            <option value="">All Positions</option>
            <option value="Instructor">Instructor</option>
            <option value="Adviser">Adviser</option>
            <option value="Chairman">Chairman</option>
            <option value="Dean">Dean</option>
          </select>
          <select
            value={filters.employmentStatus}
            onChange={(e) => setFilters(prev => ({ ...prev, employmentStatus: e.target.value }))}
            className="input-field w-auto"
          >
            <option value="">All Status</option>
            <option value="Full Time">Full Time</option>
            <option value="Part Time">Part Time</option>
          </select>
          <button type="submit" className="btn-primary">Search</button>
        </form>
      </Card>

      {/* Teachers Table */}
      <Card>
        {loading ? (
          <div className="text-center py-10">Loading...</div>
        ) : teachers.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Name</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Email</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Position</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Employment</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Capstone</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Actions</th>
                </tr>
              </thead>
              <tbody>
                {teachers.map((teacher) => (
                  <tr key={teacher.id} className="border-b border-secondary-100 hover:bg-secondary-50">
                    <td className="py-3 px-4 font-medium">
                      {teacher.first_name} {teacher.last_name}
                    </td>
                    <td className="py-3 px-4">{teacher.email}</td>
                    <td className="py-3 px-4">{teacher.position}</td>
                    <td className="py-3 px-4">
                      <span className={`px-3 py-1 rounded-full text-sm ${
                        teacher.employment_status === 'Full Time'
                          ? 'bg-green-100 text-green-700'
                          : 'bg-yellow-100 text-yellow-700'
                      }`}>
                        {teacher.employment_status}
                      </span>
                    </td>
                    <td className="py-3 px-4">
                      {teacher.capstone_adviser_available ? (
                        <span className="flex items-center gap-1 text-green-600">
                          <ToggleRight className="w-4 h-4" /> Available
                        </span>
                      ) : (
                        <span className="flex items-center gap-1 text-secondary-400">
                          <ToggleLeft className="w-4 h-4" /> Unavailable
                        </span>
                      )}
                    </td>
                    <td className="py-3 px-4">
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => openViewModal(teacher)}
                          className="p-2 text-secondary-500 hover:bg-secondary-100 rounded"
                          title="View"
                        >
                          <Eye className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => openEditModal(teacher)}
                          className="p-2 text-blue-500 hover:bg-blue-50 rounded"
                          title="Edit"
                        >
                          <Edit className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => handleResetPassword(teacher.id)}
                          className="p-2 text-orange-500 hover:bg-orange-50 rounded"
                          title="Reset Password"
                        >
                          <Key className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => handleDeleteTeacher(teacher.id)}
                          className="p-2 text-red-500 hover:bg-red-50 rounded"
                          title="Delete"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-10 text-secondary-500">
            No teachers found
          </div>
        )}
      </Card>

      {/* Add Teacher Modal */}
      <Modal
        isOpen={showAddModal}
        onClose={() => setShowAddModal(false)}
        title="Add New Teacher"
        size="large"
      >
        <form onSubmit={handleAddTeacher} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="label">Email *</label>
              <input
                type="email"
                value={formData.email}
                onChange={(e) => setFormData(prev => ({ ...prev, email: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Password *</label>
              <input
                type="password"
                value={formData.password}
                onChange={(e) => setFormData(prev => ({ ...prev, password: e.target.value }))}
                className="input-field"
                required
                minLength={6}
              />
            </div>
            <div>
              <label className="label">First Name *</label>
              <input
                type="text"
                value={formData.firstName}
                onChange={(e) => setFormData(prev => ({ ...prev, firstName: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Last Name *</label>
              <input
                type="text"
                value={formData.lastName}
                onChange={(e) => setFormData(prev => ({ ...prev, lastName: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Position</label>
              <select
                value={formData.position}
                onChange={(e) => setFormData(prev => ({ ...prev, position: e.target.value }))}
                className="input-field"
              >
                <option value="Instructor">Instructor</option>
                <option value="Adviser">Adviser</option>
                <option value="Chairman">Chairman</option>
                <option value="Dean">Dean</option>
              </select>
            </div>
            <div>
              <label className="label">Employment Status</label>
              <select
                value={formData.employmentStatus}
                onChange={(e) => setFormData(prev => ({ ...prev, employmentStatus: e.target.value }))}
                className="input-field"
              >
                <option value="Full Time">Full Time</option>
                <option value="Part Time">Part Time</option>
              </select>
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={() => setShowAddModal(false)} className="btn-secondary flex-1">
              Cancel
            </button>
            <button type="submit" disabled={saving} className="btn-primary flex-1">
              {saving ? 'Adding...' : 'Add Teacher'}
            </button>
          </div>
        </form>
      </Modal>

      {/* Edit Teacher Modal */}
      <Modal
        isOpen={showEditModal}
        onClose={() => setShowEditModal(false)}
        title="Edit Teacher"
        size="large"
      >
        <form onSubmit={handleUpdateTeacher} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="label">First Name</label>
              <input
                type="text"
                value={formData.firstName}
                onChange={(e) => setFormData(prev => ({ ...prev, firstName: e.target.value }))}
                className="input-field"
              />
            </div>
            <div>
              <label className="label">Last Name</label>
              <input
                type="text"
                value={formData.lastName}
                onChange={(e) => setFormData(prev => ({ ...prev, lastName: e.target.value }))}
                className="input-field"
              />
            </div>
            <div>
              <label className="label">Position</label>
              <select
                value={formData.position}
                onChange={(e) => setFormData(prev => ({ ...prev, position: e.target.value }))}
                className="input-field"
              >
                <option value="Instructor">Instructor</option>
                <option value="Adviser">Adviser</option>
                <option value="Chairman">Chairman</option>
                <option value="Dean">Dean</option>
              </select>
            </div>
            <div>
              <label className="label">Employment Status</label>
              <select
                value={formData.employmentStatus}
                onChange={(e) => setFormData(prev => ({ ...prev, employmentStatus: e.target.value }))}
                className="input-field"
              >
                <option value="Full Time">Full Time</option>
                <option value="Part Time">Part Time</option>
              </select>
            </div>
            <div>
              <label className="label">Section Advisory</label>
              <input
                type="text"
                value={formData.sectionAdvisory}
                onChange={(e) => setFormData(prev => ({ ...prev, sectionAdvisory: e.target.value }))}
                className="input-field"
              />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={() => setShowEditModal(false)} className="btn-secondary flex-1">
              Cancel
            </button>
            <button type="submit" disabled={saving} className="btn-primary flex-1">
              {saving ? 'Updating...' : 'Update Teacher'}
            </button>
          </div>
        </form>
      </Modal>

      {/* View Teacher Modal */}
      <Modal
        isOpen={showViewModal}
        onClose={() => setShowViewModal(false)}
        title="Teacher Details"
        size="large"
      >
        {selectedTeacher && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-secondary-500">Full Name</p>
                <p className="font-medium">{selectedTeacher.first_name} {selectedTeacher.middle_name} {selectedTeacher.last_name}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Email</p>
                <p className="font-medium">{selectedTeacher.email}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Position</p>
                <p className="font-medium">{selectedTeacher.position}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Employment Status</p>
                <p className="font-medium">{selectedTeacher.employment_status}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Section Advisory</p>
                <p className="font-medium">{selectedTeacher.section_advisory || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Years of Service</p>
                <p className="font-medium">{selectedTeacher.years_of_service || 0}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Degree</p>
                <p className="font-medium">{selectedTeacher.degree || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">University</p>
                <p className="font-medium">{selectedTeacher.university || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Capstone Adviser</p>
                <p className="font-medium">{selectedTeacher.capstone_adviser_available ? 'Available' : 'Unavailable'}</p>
              </div>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default ManageTeachers;
